SELECT applicant_id, AVG(mdcat_marks_obtained) AS average_marks
FROM mdcat_scores
GROUP BY applicant_id;

SELECT applicant_id, COUNT(document_id) AS document_count
FROM applicant_documents
GROUP BY applicant_id;

SELECT LENGTH(document_type) 
FROM applicant_documents 
WHERE document_id = 1;

SELECT AVG(mdcat_marks_obtained) AS average_marks
FROM mdcat_scores
WHERE mdcat_marks_obtained > (mdcat_marks_total * 0.4);
